import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();
  const [proposals, setProposals] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState({ description:"", github_link:"", live_link:"" });
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState("");

  useEffect(() => {
    Promise.all([API.get("/proposals/my"), API.get("/submissions/my")]).then(([pr, sr]) => {
      setProposals((pr.data||[]).filter(p=>p.status==="accepted"));
      setSubmissions(sr.data||[]);
      setLoading(false);
    }).catch(()=>setLoading(false));
  }, []);

  const getSub = (pid) => submissions.find(s=>s.project_id===pid);

  const handleSubmit = async () => {
    if (!form.description) return alert("Description is required");
    setSubmitting(true);
    try {
      await API.post("/submissions", { project_id: modal.project_id, description: form.description, github_link: form.github_link, live_link: form.live_link });
      const r = await API.get("/submissions/my");
      setSubmissions(r.data||[]);
      setSuccess("Work submitted!"); setTimeout(()=>{setSuccess("");setModal(null);},1500);
    } catch(e){ alert(e.response?.data?.message||"Error"); }
    setSubmitting(false);
  };

  const statusColor = (s) => ({ approved:"#4ade80", revision:"#fb923c", submitted:"#38bdf8" }[s]||"#94a3b8");

  const S = {
    page: { background:"#0f172a", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" },
    title: { fontSize:"24px", fontWeight:"700", color:"#f1f5f9", marginBottom:"4px" },
    sub: { fontSize:"13px", color:"#64748b", marginBottom:"28px" },
    card: { background:"#1e293b", border:"1px solid #334155", borderRadius:"14px", padding:"20px", marginBottom:"14px" },
    row: { display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"12px" },
    pTitle: { fontSize:"16px", fontWeight:"700", color:"#f1f5f9" },
    meta: { fontSize:"12px", color:"#64748b", marginTop:"4px" },
    bid: { color:"#4ade80", fontWeight:"800" },
    submitBtn: { padding:"9px 18px", borderRadius:"8px", border:"none", background:"linear-gradient(135deg,#0d9488,#0891b2)", color:"white", fontSize:"12px", fontWeight:"700", cursor:"pointer" },
    updateBtn: { padding:"9px 18px", borderRadius:"8px", border:"1px solid #334155", background:"transparent", color:"#94a3b8", fontSize:"12px", fontWeight:"700", cursor:"pointer" },
    subBox: { background:"#0f172a", border:"1px solid #334155", borderRadius:"10px", padding:"14px", marginTop:"12px" },
    subStatus: (s) => ({ display:"inline-block", padding:"3px 12px", borderRadius:"20px", fontSize:"10px", fontWeight:"700", background:`${statusColor(s)}20`, color:statusColor(s), border:`1px solid ${statusColor(s)}40`, textTransform:"capitalize", marginBottom:"8px" }),
    link: { color:"#38bdf8", fontSize:"12px", marginRight:"14px", textDecoration:"none" },
    overlay: { position:"fixed", inset:0, background:"rgba(0,0,0,0.75)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:50, padding:"20px" },
    modal: { background:"#1e293b", border:"1px solid #334155", borderRadius:"16px", padding:"28px", width:"100%", maxWidth:"440px" },
    mLabel: { fontSize:"11px", fontWeight:"600", color:"#94a3b8", display:"block", marginBottom:"4px", textTransform:"uppercase", letterSpacing:"0.8px" },
    mInput: { width:"100%", padding:"10px 12px", background:"#0f172a", border:"1px solid #334155", borderRadius:"8px", color:"#f1f5f9", fontSize:"13px", outline:"none", boxSizing:"border-box", marginBottom:"12px" },
  };

  if (loading) return <div style={{...S.page,display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:"#2dd4bf"}}>Loading...</span></div>;

  return (
    <div style={S.page}>
      <h1 style={S.title}>My Projects</h1>
      <p style={S.sub}>Submit your completed work for client review</p>

      {success && <div style={{background:"rgba(74,222,128,0.1)",border:"1px solid rgba(74,222,128,0.3)",color:"#4ade80",padding:"12px 16px",borderRadius:"10px",marginBottom:"16px",fontSize:"13px"}}>🎉 {success}</div>}

      {proposals.length === 0 ? (
        <div style={{textAlign:"center",padding:"60px",color:"#475569"}}>
          <div style={{fontSize:"40px",marginBottom:"12px"}}>📭</div>
          <p>No accepted projects yet.</p>
          <button onClick={()=>navigate("/freelancer/find-projects")} style={{marginTop:"12px",padding:"9px 20px",borderRadius:"8px",border:"none",background:"linear-gradient(135deg,#0d9488,#0891b2)",color:"white",fontSize:"13px",fontWeight:"700",cursor:"pointer"}}>Browse Projects</button>
        </div>
      ) : proposals.map(p => {
        const sub = getSub(p.project_id);
        return (
          <div key={p.id} style={S.card}>
            <div style={S.row}>
              <div>
                <p style={S.pTitle}>{p.project_title}</p>
                <p style={S.meta}>Budget: <span style={S.bid}>₹{p.project_budget||p.budget}</span> · Your Bid: <span style={S.bid}>₹{p.bid}</span></p>
              </div>
              {!sub
                ? <button style={S.submitBtn} onClick={()=>{setModal(p);setForm({description:"",github_link:"",live_link:""});}}>🚀 Submit Work</button>
                : sub.status==="revision"
                  ? <button style={{...S.submitBtn,background:"linear-gradient(135deg,#d97706,#b45309)"}} onClick={()=>{setModal(p);setForm({description:sub.description||"",github_link:sub.github_link||"",live_link:sub.live_link||""});}}>🔄 Resubmit</button>
                  : <button style={S.updateBtn}>Submitted ✓</button>
              }
            </div>
            {sub && (
              <div style={S.subBox}>
                <span style={S.subStatus(sub.status)}>{sub.status}</span>
                {sub.description && <p style={{fontSize:"13px",color:"#94a3b8",margin:"0 0 8px"}}>{sub.description}</p>}
                <div>
                  {sub.github_link && <a href={sub.github_link} target="_blank" rel="noreferrer" style={S.link}>🔗 GitHub</a>}
                  {sub.live_link && <a href={sub.live_link} target="_blank" rel="noreferrer" style={S.link}>🌐 Live Demo</a>}
                </div>
                {sub.feedback && <div style={{marginTop:"10px",background:"rgba(251,146,60,0.1)",border:"1px solid rgba(251,146,60,0.3)",borderRadius:"8px",padding:"10px",fontSize:"12px",color:"#fb923c"}}>💬 {sub.feedback}</div>}
                {sub.status==="approved" && <div style={{marginTop:"10px",background:"rgba(74,222,128,0.1)",border:"1px solid rgba(74,222,128,0.3)",borderRadius:"8px",padding:"10px",fontSize:"12px",color:"#4ade80"}}>✅ Approved! Great work!</div>}
              </div>
            )}
          </div>
        );
      })}

      {modal && (
        <div style={S.overlay} onClick={e=>e.target===e.currentTarget&&setModal(null)}>
          <div style={S.modal}>
            {success ? (
              <div style={{textAlign:"center",padding:"20px"}}><div style={{fontSize:"40px",marginBottom:"10px"}}>🎉</div><p style={{color:"#4ade80",fontWeight:"700"}}>{success}</p></div>
            ) : (
              <>
                <h2 style={{fontSize:"17px",fontWeight:"700",color:"#f1f5f9",marginBottom:"4px"}}>Submit Work</h2>
                <p style={{fontSize:"12px",color:"#64748b",marginBottom:"20px"}}>{modal.project_title}</p>
                <label style={S.mLabel}>Description *</label>
                <textarea style={{...S.mInput,height:"80px",resize:"none"}} placeholder="Describe what you built..." value={form.description} onChange={e=>setForm({...form,description:e.target.value})} />
                <label style={S.mLabel}>GitHub Link</label>
                <input style={S.mInput} type="url" placeholder="https://github.com/..." value={form.github_link} onChange={e=>setForm({...form,github_link:e.target.value})} />
                <label style={S.mLabel}>Live Demo <span style={{color:"#475569",fontWeight:"400"}}>(optional)</span></label>
                <input style={S.mInput} type="url" placeholder="https://..." value={form.live_link} onChange={e=>setForm({...form,live_link:e.target.value})} />
                <div style={{display:"flex",gap:"10px"}}>
                  <button onClick={handleSubmit} disabled={submitting} style={{flex:1,padding:"10px",borderRadius:"8px",border:"none",background:"linear-gradient(135deg,#0d9488,#0891b2)",color:"white",fontWeight:"700",cursor:"pointer",opacity:submitting?.7:1}}>{submitting?"Submitting...":"Submit Project"}</button>
                  <button onClick={()=>setModal(null)} style={{padding:"10px 18px",borderRadius:"8px",border:"1px solid #334155",background:"transparent",color:"#94a3b8",cursor:"pointer"}}>Cancel</button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
